/* Berg PC — Marketing website parts. Exports to window.BergWeb.
   Composes design-system primitives from window.BergPCDesignSystem_eb13e3. */
const DS = window.BergPCDesignSystem_eb13e3;
const { Button, Badge, Card, CardHeader, Stat, Alert, Field, Input, Select, Textarea, Checkbox, Radio } = DS;
const Ico = ({ n, s = 18, ...p }) => <i data-lucide={n} style={{ width: s, height: s }} {...p}></i>;

const LOGO = "data:image/png;base64,";
const LOGO_REV = "data:image/png;base64,";

/* ---------- Utility + Header ---------- */
function TopBar() {
  return (
    <div style={{ background: "var(--ink-950)", color: "var(--ink-200)", fontSize: 12.5, fontFamily: "var(--font-ui)" }}>
      <div style={{ maxWidth: 1200, margin: "0 auto", padding: "8px 28px", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
        <span style={{ display: "inline-flex", alignItems: "center", gap: 8, letterSpacing: ".04em" }}>
          <Ico n="map-pin" s={14} /> 24 Greenway Plaza, Suite 1800 · Houston, Texas
        </span>
        <span style={{ display: "inline-flex", alignItems: "center", gap: 18 }}>
          <span style={{ display: "inline-flex", alignItems: "center", gap: 7, color: "var(--stone-300)" }}><Ico n="scale" s={14}/> Contingency — no recovery, no fee</span>
          <a href="tel:+12818576666" style={{ color: "var(--cream)", textDecoration: "none", display: "inline-flex", alignItems: "center", gap: 7, fontWeight: 600 }}><Ico n="phone" s={14}/> 281 857-6666</a>
        </span>
      </div>
    </div>
  );
}

function Header({ route, go }) {
  const nav = [["Team", "team"], ["Business Litigation", "business"], ["Crypto Litigation", "crypto"], ["Blog", "blog"]];
  return (
    <header style={{ background: "var(--cream)", borderBottom: "1px solid var(--border-subtle)", position: "sticky", top: 0, zIndex: 40 }}>
      <div style={{ maxWidth: 1200, margin: "0 auto", padding: "14px 28px", display: "flex", alignItems: "center", justifyContent: "space-between", gap: 24 }}>
        <a href="#" onClick={(e)=>{e.preventDefault();go("home");}} style={{ display: "flex", alignItems: "center" }}>
          <img src={LOGO} alt="Berg PC" style={{ height: 52 }} />
        </a>
        <nav style={{ display: "flex", alignItems: "center", gap: 28, fontFamily: "var(--font-ui)", fontSize: 14.5, fontWeight: 500 }}>
          {nav.map(([label, id]) => (
            <a key={id} href="#" onClick={(e)=>{e.preventDefault();go(id==="crypto"?"crypto":"home");}}
               style={{ color: route === id ? "var(--ink-900)" : "var(--ink-700)", textDecoration: "none", display: "inline-flex", alignItems: "center", gap: 5 }}>
              {label}{(id==="business"||id==="crypto") && <Ico n="chevron-down" s={14}/>}
            </a>
          ))}
        </nav>
        <Button variant="primary" onClick={()=>go("intake")}>Tell Us About Your Case</Button>
      </div>
    </header>
  );
}

/* ---------- Hero ---------- */
function Hero({ go }) {
  return (
    <section style={{ background: "var(--navy-900)", color: "var(--cream)", position: "relative", overflow: "hidden" }}>
      <div style={{ maxWidth: 1200, margin: "0 auto", padding: "84px 28px 76px", display: "grid", gridTemplateColumns: "1.05fr 0.95fr", gap: 56, alignItems: "center" }}>
        <div>
          <div style={{ fontSize: 12.5, fontWeight: 600, letterSpacing: ".18em", textTransform: "uppercase", color: "var(--stone-300)" }}>Business &amp; Cryptocurrency Litigation</div>
          <hr style={{ width: 54, height: 3, background: "var(--stone-400)", border: 0, margin: "20px 0 24px" }} />
          <h1 style={{ fontFamily: "var(--font-serif)", fontWeight: 600, fontSize: 52, lineHeight: 1.06, letterSpacing: "-0.02em", color: "var(--cream)", margin: 0 }}>
            Senior attorneys and digital forensics experts, working together.
          </h1>
          <p style={{ fontFamily: "var(--font-ui)", fontSize: 18, lineHeight: 1.6, color: "var(--navy-100)", maxWidth: 520, margin: "22px 0 32px" }}>
            We trace stolen cryptocurrency across the blockchain, identify who took it, and pursue recovery through the courts — for victims, businesses, and institutions.
          </p>
          <div style={{ display: "flex", gap: 14, alignItems: "center", flexWrap: "wrap" }}>
            <Button variant="accent" size="lg" onClick={()=>go("intake")} iconRight={<Ico n="arrow-right"/>}>Start your recovery</Button>
            <Button variant="ghost" size="lg" style={{ color: "var(--cream)", border: "1px solid var(--navy-600)" }} onClick={()=>go("crypto")}>How recovery works</Button>
          </div>
        </div>
        <PhotoSlot label="Geoff Berg — firm introduction" tall icon="play" />
      </div>
    </section>
  );
}

/* photo placeholder: navy field, mark watermark, caption */
function PhotoSlot({ label, tall, icon = "image" }) {
  return (
    <div style={{ position: "relative", borderRadius: "var(--radius-lg)", overflow: "hidden", border: "1px solid var(--navy-700)",
      background: "var(--navy-800)", minHeight: tall ? 360 : 220, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 12 }}>
      <img src={LOGO_REV} alt="" style={{ height: 60, opacity: 0.22 }} />
      <span style={{ display:"inline-flex", alignItems:"center", gap:8, fontFamily: "var(--font-ui)", fontSize: 12.5, letterSpacing: ".08em", textTransform: "uppercase", color: "var(--navy-300)" }}>
        <Ico n={icon} s={15}/> {label}
      </span>
    </div>
  );
}

/* ---------- Press band ---------- */
function PressBand() {
  const press = ["NPR", "CBS NEWS", "WIRED", "CNN", "CNBC", "FOX", "THE WASHINGTON POST"];
  return (
    <section style={{ background: "var(--cream)", borderBottom: "1px solid var(--border-subtle)" }}>
      <div style={{ maxWidth: 1200, margin: "0 auto", padding: "26px 28px", display: "flex", alignItems: "center", gap: 30, flexWrap: "wrap", justifyContent: "center" }}>
        <span style={{ fontFamily: "var(--font-ui)", fontSize: 12, fontWeight: 600, letterSpacing: ".16em", textTransform: "uppercase", color: "var(--ink-400)" }}>As featured in</span>
        {press.map(p => (
          <span key={p} style={{ fontFamily: "var(--font-serif)", fontSize: 19, fontWeight: 600, color: "var(--ink-400)", letterSpacing: ".02em" }}>{p}</span>
        ))}
      </div>
    </section>
  );
}

/* ---------- Practice areas ---------- */
function Practice({ go }) {
  const areas = [
    { t: "Business Litigation", icon: "briefcase", items: ["Breach of Contract", "Partnership Disputes", "Business Divorce", "Non-Compete Disputes"] },
    { t: "Crypto Litigation", icon: "bitcoin", items: ["Crypto Fraud & Recovery", "Crypto Business Transactions", "Coinbase Data Breach", "Meta Crypto Scam Ads"] },
  ];
  return (
    <section style={{ background: "var(--cream)" }}>
      <div style={{ maxWidth: 1200, margin: "0 auto", padding: "76px 28px" }}>
        <SectionHead eyebrow="Practice Areas" title="Where we focus" />
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 24, marginTop: 36 }}>
          {areas.map(a => (
            <Card key={a.t} padding="lg">
              <div style={{ display: "flex", alignItems: "center", gap: 13, marginBottom: 18 }}>
                <span style={{ display: "inline-flex", alignItems: "center", justifyContent: "center", width: 46, height: 46, borderRadius: "var(--radius-md)", background: "var(--navy-900)", color: "var(--stone-300)" }}><Ico n={a.icon} s={22}/></span>
                <h3 style={{ fontFamily: "var(--font-serif)", fontSize: 24, fontWeight: 600, color: "var(--ink-900)", margin: 0 }}>{a.t}</h3>
              </div>
              <div style={{ display: "flex", flexDirection: "column" }}>
                {a.items.map(it => (
                  <a key={it} href="#" onClick={(e)=>{e.preventDefault(); if(it.startsWith("Crypto Fraud")) go("crypto");}}
                     style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "13px 0", borderTop: "1px solid var(--border-subtle)", color: "var(--ink-700)", textDecoration: "none", fontFamily: "var(--font-ui)", fontSize: 15.5 }}
                     onMouseEnter={e=>e.currentTarget.style.color="var(--ink-900)"} onMouseLeave={e=>e.currentTarget.style.color="var(--ink-700)"}>
                    {it} <Ico n="arrow-up-right" s={16}/>
                  </a>
                ))}
              </div>
            </Card>
          ))}
        </div>
      </div>
    </section>
  );
}

function SectionHead({ eyebrow, title, light }) {
  return (
    <div>
      <div style={{ fontFamily: "var(--font-ui)", fontSize: 12.5, fontWeight: 600, letterSpacing: ".18em", textTransform: "uppercase", color: light ? "var(--stone-300)" : "var(--stone-600)" }}>{eyebrow}</div>
      <hr style={{ width: 54, height: 3, background: "var(--stone-400)", border: 0, margin: "16px 0 0" }} />
      <h2 style={{ fontFamily: "var(--font-serif)", fontSize: 38, fontWeight: 600, letterSpacing: "-0.02em", color: light ? "var(--cream)" : "var(--ink-900)", margin: "18px 0 0", maxWidth: 640 }}>{title}</h2>
    </div>
  );
}

/* ---------- Results band ---------- */
function Results() {
  return (
    <section style={{ background: "var(--navy-900)", color: "var(--cream)" }}>
      <div style={{ maxWidth: 1200, margin: "0 auto", padding: "70px 28px" }}>
        <SectionHead eyebrow="Recent Results" title="Outcomes that hold up in court" light />
        <div style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: 28, marginTop: 44 }}>
          {[
            ["$500,000", "Stolen crypto returned to a Texas family", "2025"],
            ["30 wallets", "Frozen by injunction — first of its kind in Texas", "2024"],
            ["$100M+", "In digital assets traced across cross-border cases", "To date"],
          ].map(([v, c, y]) => (
            <div key={v} style={{ borderTop: "2px solid var(--stone-500)", paddingTop: 20 }}>
              <div style={{ fontFamily: "var(--font-serif)", fontSize: 44, fontWeight: 600, color: "var(--cream)", lineHeight: 1, letterSpacing: "-0.02em" }}>{v}</div>
              <p style={{ fontFamily: "var(--font-ui)", fontSize: 15, color: "var(--navy-100)", margin: "14px 0 8px", lineHeight: 1.5 }}>{c}</p>
              <span style={{ fontFamily: "var(--font-mono)", fontSize: 12, color: "var(--stone-300)" }}>{y}</span>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

